func TestTrajectory_Complete(t *testing.T) {
	tests := []struct {
		name        string
		outcome     string
		steps       []agentic.TrajectoryStep
		wantOutcome string
	}{
		{
			name:    "complete with success",
			outcome: "complete",
			steps: []agentic.TrajectoryStep{
				{
					Timestamp: time.Now(),
					StepType:  "model_call",
					RequestID: "req-1",
					TokensIn:  100,
					TokensOut: 200,
					Duration:  1000,
				},
			},
			wantOutcome: "complete",
		},
		{
			name:    "complete with failure",
			outcome: "failed",
			steps: []agentic.TrajectoryStep{
				{
					Timestamp: time.Now(),
					StepType:  "model_call",
					RequestID: "req-1",
					TokensIn:  50,
					TokensOut: 100,
					Duration:  500,
				},
			},
			wantOutcome: "failed",
		},
		{
			name:    "complete with max iterations",
			outcome: "max_iterations",
			steps: []agentic.TrajectoryStep{
				{
					Timestamp: time.Now(),
					StepType:  "model_call",
					RequestID: "req-1",
					Duration:  1000,
				},
			},
			wantOutcome: "max_iterations",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			startTime := time.Now().UTC().Add(-5 * time.Second)
			trajectory := agentic.Trajectory{
				LoopID:    "loop-test",
				StartTime: startTime,
				Steps:     tt.steps,
			}

			trajectory.Complete(tt.outcome)

			if trajectory.Outcome != tt.wantOutcome {
				t.Errorf("Outcome = %v, want %v", trajectory.Outcome, tt.wantOutcome)
			}
			if trajectory.EndTime == nil {
				t.Errorf("EndTime should not be nil after Complete()")
			}
			if trajectory.Duration <= 0 {
				t.Errorf("Duration should be positive after Complete(), got %d", trajectory.Duration)
			}
			// Duration should be at least 5 seconds (time since start)
			minDuration := int64(5000) // 5 seconds in milliseconds
			if trajectory.Duration < minDuration {
				t.Errorf("Duration = %d ms, expected at least %d ms", trajectory.Duration, minDuration)
			}
		})
	}
}

